import{_ as e,o as s,c as n,O as i}from"./chunks/framework.0d5b6918.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"en/logo-design/index.md","filePath":"en/logo-design/index.md","lastUpdated":1776135989000}'),t={name:"en/logo-design/index.md"};function r(l,a,c,p,o,d){return s(),n("div",null,a[0]||(a[0]=[i('<div class="brand-page-shell"><section class="brand-hero brand-hero--logo"><div><p class="brand-kicker">Brand System</p><h1>ExecFabric Logo Design Direction</h1><div class="brand-hero__panel"><span class="brand-pill">Direction Note</span><strong>The goal is not to make a flashy icon. It is to establish a reusable product identity system.</strong><p>The logo should express intelligence, flow, control, and execution at the same time, while staying stable across docs, admin screens, the CLI, and small icon use.</p></div><p class="brand-lead"> This is not a single icon sketch. It is a design brief for building one unified brand identity system around <strong>intelligent dispatch, experience as assets, safe control, and automated flow</strong>. </p><div class="brand-chip-list"><span class="brand-chip">intelligent dispatch</span><span class="brand-chip">experience as assets</span><span class="brand-chip">safe control</span><span class="brand-chip">automated flow</span></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // BRAND SYSTEM</span><span>BRAND 02</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">brand_core</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">intelligence</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">execution</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">flow</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">visual_tokens</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">loop</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">control_boundary</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">trigger_point</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">usage</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">docs</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">admin</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">cli</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__string">app_icon</span></span></div><div class="matrix-panel__callout">SYSTEMATIC BRAND / NOT DECORATION</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">tone</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">steady</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">shape</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">identifiable</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">fit</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">multi_surface</span></span></div></div></div></section><section class="brand-grid brand-grid--four"><article class="brand-card"><p class="brand-kicker">Keyword</p><h3>Intelligence</h3><p>It should feel like a brain and decision center, not an ordinary decorative shape.</p></article><article class="brand-card"><p class="brand-kicker">Keyword</p><h3>Flow</h3><p>It should show data, energy, path, and direction rather than a static object.</p></article><article class="brand-card"><p class="brand-kicker">Keyword</p><h3>Control</h3><p>It should carry signals of boundary, aggregation, system dispatch, and controllable risk.</p></article><article class="brand-card"><p class="brand-kicker">Keyword</p><h3>Precision</h3><p>It should reflect efficient triggering and decisive execution, with the tension of &quot;it will run the next second.&quot;</p></article></section><section class="brand-card"><p class="brand-kicker">Core Composition</p><h2>Core design elements</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><span class="brand-pill">01</span><h3>Main symbol</h3><p>Use an abstract transformation of the right side of the Chinese character <code>智</code>, especially its inner square structure, and merge it with neural circuitry or data-flow patterns to form the core symbol.</p></article><article class="brand-card brand-card--nested"><span class="brand-pill">02</span><h3>Encircling structure</h3><p>Wrap or pierce the main symbol with a ring or an <code>∞</code> variant to express cycle, network, ecosystem, and controlled boundary.</p></article><article class="brand-card brand-card--nested"><span class="brand-pill">03</span><h3>Accent marker</h3><p>Add a minimal lightning or arrow mark at the core to represent dispatch trigger, intelligent decision, and precise execution.</p></article></div></section><section class="brand-card"><p class="brand-kicker">Directions</p><h2>Three design directions</h2><div class="brand-direction-grid"><article class="brand-direction-card"><span class="brand-pill">Direction 01</span><h3>Intelligent Cube</h3><p>Emphasizes architecture, system thinking, and control. This direction fits a stronger platform and enterprise tone.</p><ul class="brand-list"><li>Core image: a semi-transparent cube, internal luminous data flow, and a lightning-like trigger point</li><li>Design language: firm geometry, clear structure, and strong internal tension</li><li>Suggested colors: deep-space gray or matte silver with a blue-to-cyan gradient</li></ul></article><article class="brand-direction-card"><span class="brand-pill">Direction 02</span><h3>Neural Surge</h3><p>Emphasizes the intelligent center, connection network, and dispatch diffusion, with a more frontier and agile AI feeling.</p><ul class="brand-list"><li>Core image: a neural-network structure close to the letter <code>Z</code> with a central light point</li><li>Design language: organic, luminous, with visible node connections and a stronger sense of intelligent life</li><li>Suggested colors: a deep blue base with cyan or purple central highlights and a white dispatch wave</li></ul></article><article class="brand-direction-card"><span class="brand-pill">Direction 03</span><h3>Infinite Gateway</h3><p>Emphasizes workflow, passage, controlled circulation, and open-ended expansion. This direction is the closest to the product meaning of &quot;ExecFabric.&quot;</p><ul class="brand-list"><li>Core image: a Mobius strip or <code>∞</code> variant, plus a gate or bridge metaphor and a penetrating light beam</li><li>Design language: elegant, cyclical, streamlined, with a sense of path philosophy</li><li>Suggested colors: a technology blue or deep-violet gradient with bright route bands and white beams</li></ul></article></div></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Current Recommendation</p><h2>The recommended path right now</h2><p class="brand-lead"> The current recommendation is to use the overall structure of <strong>Infinite Gateway</strong> as the skeleton, absorb the intelligent connection feel of <strong>Neural Surge</strong>, and add the local geometric control feel of <strong>Intelligent Cube</strong>. </p><p>This combination fits ExecFabric&#39;s current platform meaning better: it is neither just a tool nor just a chat product. It is an execution platform that dispatches real capabilities inside controlled boundaries.</p></article><article class="brand-card"><p class="brand-kicker">Next Assets</p><h2>The next visual assets to add</h2><ul class="brand-list"><li>black-and-white directions and single-color standards</li><li>reverse-color versions, favicon tests, and app-icon thumbnail tests</li><li>icon-only versions and Chinese-English combination marks</li><li>adaptation drafts for GitHub, web, admin, and CLI scenarios</li></ul></article></section></div>',1)]))}const h=e(t,[["render",r]]);export{m as __pageData,h as default};
